import{_ as t,o,c as s,a0 as a}from"./chunks/framework.BWpMpcZ2.js";const p=JSON.parse('{"title":"General Settings","description":"","frontmatter":{},"headers":[],"relativePath":"configuration/general.md","filePath":"configuration/general.md"}'),r={name:"configuration/general.md"};function n(i,e,l,c,d,h){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h1><p>The General settings tab controls your workspace, default editor mode, and AI response length.</p><h2 id="workspace-directory" tabindex="-1">Workspace Directory <a class="header-anchor" href="#workspace-directory" aria-label="Permalink to &quot;Workspace Directory&quot;">​</a></h2><p>A <strong>workspace</strong> is a folder on your computer that contains your content project. It can hold chapters, character sheets, style guides, world-building notes -- whatever your project needs.</p><p>margin comes with a <code>sample-workspace</code> that has example files to help you get started. To use your own:</p><ol><li><strong>Type</strong> the absolute path to your folder (e.g., <code>/Users/name/my-project</code>), or</li><li>Click <strong>Browse...</strong> to pick a folder using your system&#39;s file picker, then</li><li>Click <strong>Link Path</strong>.</li></ol><p>To reset to the default sample workspace, click <strong>Reset to default fallback workspace</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Your workspace path is stored in <code>settings.json</code> and never sent anywhere. It&#39;s only used to locate your files.</p></div><h2 id="default-mode" tabindex="-1">Default Mode <a class="header-anchor" href="#default-mode" aria-label="Permalink to &quot;Default Mode&quot;">​</a></h2><p>Choose which AI assist mode opens by default:</p><ul><li><strong>Edit Document</strong>: Highlight text in the editor, describe the change you want, and the AI rewrites it inline.</li><li><strong>Conversational Chat</strong>: Ask questions, brainstorm ideas, or have back-and-forth conversations about your content. The AI can see your cursor position and any selected text.</li></ul><p>You can switch between modes at any time while using the AI assistant.</p><h2 id="default-verbosity" tabindex="-1">Default Verbosity <a class="header-anchor" href="#default-verbosity" aria-label="Permalink to &quot;Default Verbosity&quot;">​</a></h2><p>Controls how much text the AI generates per response:</p><ul><li><strong>No Limit</strong>: Let the AI decide.</li><li><strong>Concise</strong>: Short responses (~250 tokens).</li><li><strong>Balanced</strong>: Moderate responses (~500 tokens).</li><li><strong>Expansive</strong>: Detailed responses (~1000 tokens).</li></ul><p>The default is <strong>Balanced</strong>, which works well for most situations.</p><div class="warning custom-block"><p class="custom-block-title">Higher verbosity settings consume more tokens. If you&#39;re using a smaller local model or have a limited context window, stick with <strong>Concise</strong> or <strong>Balanced</strong>.</p></div>',17)])])}const g=t(r,[["render",n]]);export{p as __pageData,g as default};
